Your route is likely vulnerable to **forced browsing** (also called Insecure Direct Object Reference or IDOR). This vulnerability was responsible for exposing 885 million sensitive documents at First American Financial Corporation, where attackers simply incremented document IDs in URLs to access other customers' private records.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// VULNERABLE: No authorization check - any authenticated user can access ANY document
app.get('/api/documents/:id', authenticateUser, async (req, res) => {
  try {
    const documentId = req.params.id;

    // Fetches document without verifying ownership
    const result = await pool.query(
      'SELECT * FROM documents WHERE id = $1',
      [documentId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Document not found' });
    }

    // Returns document to any authenticated user
    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});

function authenticateUser(req, res, next) {
  // Assume JWT validation happens here
  req.user = { id: 123, role: 'user' }; // From token
  next();
}

app.listen(3000);
```

**Attack Payload**:
```bash
# User 123 is authenticated but accesses User 456's document
curl -H "Authorization: Bearer <valid_token>" \
     http://api.example.com/api/documents/99999

# Attacker can enumerate all documents by incrementing IDs
for i in {1..10000}; do
  curl -s -H "Authorization: Bearer <token>" \
       http://api.example.com/api/documents/$i >> stolen_docs.json
done
```

**Why This Is Dangerous**:
- Authentication only verifies WHO the user is, not WHAT they can access
- Sequential integer IDs are easily guessable and enumerable
- No ownership verification allows any user to access any document
- Attackers can automate mass data extraction with simple scripts

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const { v4: uuidv4 } = require('uuid');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// SECURE: Authorization check ensures user owns the document
app.get('/api/documents/:id', authenticateUser, async (req, res) => {
  try {
    const documentId = req.params.id;
    const userId = req.user.id;

    // Validate UUID format to prevent enumeration
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(documentId)) {
      return res.status(400).json({ error: 'Invalid document ID format' });
    }

    // CRITICAL: Include user_id in WHERE clause for ownership verification
    const result = await pool.query(
      'SELECT id, title, content, created_at FROM documents WHERE id = $1 AND user_id = $2',
      [documentId, userId]
    );

    if (result.rows.length === 0) {
      // Generic error prevents enumeration - don't reveal if doc exists
      return res.status(404).json({ error: 'Document not found' });
    }

    // Audit log for security monitoring
    console.log(`[AUDIT] User ${userId} accessed document ${documentId}`);

    res.json(result.rows[0]);
  } catch (error) {
    console.error(`[ERROR] Document access failed: ${error.message}`);
    res.status(500).json({ error: 'Server error' });
  }
});

function authenticateUser(req, res, next) {
  req.user = { id: 123, role: 'user' };
  next();
}

app.listen(3000);
```

**Key Security Controls**:
- **Ownership verification**: SQL query includes `user_id = $2` to ensure users can only access their own documents
- **UUID identifiers**: Non-sequential UUIDs prevent enumeration attacks (can't just increment to find other documents)
- **Consistent error responses**: Same 404 response whether document doesn't exist or user doesn't own it, preventing information leakage

Excellent question! Multi-level authorization requires a robust permission system that handles ownership, team sharing, and public access while maintaining the principle of least privilege. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');

const app = express();
app.use(helmet());

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Structured audit logging
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Rate limiting to prevent enumeration attacks
const documentLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Permission levels enum
const AccessLevel = {
  NONE: 0,
  READ: 1,
  WRITE: 2,
  ADMIN: 3
};

// Central authorization service
class DocumentAuthorizationService {
  constructor(pool) {
    this.pool = pool;
  }

  async checkAccess(userId, documentId, requiredLevel = AccessLevel.READ) {
    const client = await this.pool.connect();

    try {
      // Check multiple access paths in order of specificity
      const result = await client.query(`
        SELECT 
          d.id,
          d.title,
          d.content,
          d.visibility,
          d.user_id as owner_id,
          COALESCE(dp.access_level, 0) as direct_permission,
          COALESCE(MAX(tp.access_level), 0) as team_permission
        FROM documents d
        LEFT JOIN document_permissions dp 
          ON dp.document_id = d.id AND dp.user_id = $2
        LEFT JOIN team_members tm 
          ON tm.user_id = $2
        LEFT JOIN team_permissions tp 
          ON tp.document_id = d.id AND tp.team_id = tm.team_id
        WHERE d.id = $1
        GROUP BY d.id, d.title, d.content, d.visibility, d.user_id, dp.access_level
      `, [documentId, userId]);

      if (result.rows.length === 0) {
        return { allowed: false, reason: 'not_found' };
      }

      const doc = result.rows[0];
      let effectiveAccess = AccessLevel.NONE;
      let accessPath = 'none';

      // Priority 1: Owner has full access
      if (doc.owner_id === userId) {
        effectiveAccess = AccessLevel.ADMIN;
        accessPath = 'owner';
      }
      // Priority 2: Direct user permission
      else if (doc.direct_permission >= requiredLevel) {
        effectiveAccess = doc.direct_permission;
        accessPath = 'direct';
      }
      // Priority 3: Team-based permission
      else if (doc.team_permission >= requiredLevel) {
        effectiveAccess = doc.team_permission;
        accessPath = 'team';
      }
      // Priority 4: Public documents (read-only)
      else if (doc.visibility === 'public' && requiredLevel === AccessLevel.READ) {
        effectiveAccess = AccessLevel.READ;
        accessPath = 'public';
      }

      return {
        allowed: effectiveAccess >= requiredLevel,
        document: effectiveAccess >= requiredLevel ? doc : null,
        accessLevel: effectiveAccess,
        accessPath: accessPath,
        reason: effectiveAccess >= requiredLevel ? 'granted' : 'insufficient_permission'
      };
    } finally {
      client.release();
    }
  }
}

const authService = new DocumentAuthorizationService(pool);

// Authorization middleware factory
function requireDocumentAccess(requiredLevel) {
  return async (req, res, next) => {
    const documentId = req.params.id;
    const userId = req.user?.id;

    // Validate UUID format
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(documentId)) {
      auditLogger.warn({
        event: 'invalid_document_id',
        userId,
        documentId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(400).json({ error: 'Invalid document ID' });
    }

    try {
      const accessResult = await authService.checkAccess(userId, documentId, requiredLevel);

      // Comprehensive audit logging
      auditLogger.info({
        event: 'document_access_attempt',
        userId,
        documentId,
        requiredLevel,
        granted: accessResult.allowed,
        accessPath: accessResult.accessPath,
        ip: req.ip,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString()
      });

      if (!accessResult.allowed) {
        // Consistent error response prevents enumeration
        return res.status(404).json({ error: 'Document not found' });
      }

      req.document = accessResult.document;
      req.accessLevel = accessResult.accessLevel;
      next();
    } catch (error) {
      auditLogger.error({
        event: 'authorization_error',
        userId,
        documentId,
        error: error.message,
        timestamp: new Date().toISOString()
      });
      res.status(500).json({ error: 'Server error' });
    }
  };
}

// Route handlers with granular permissions
app.get('/api/documents/:id',
  authenticateUser,
  documentLimiter,
  requireDocumentAccess(AccessLevel.READ),
  (req, res) => {
    // Document already fetched and authorized
    const { id, title, content } = req.document;
    res.json({ id, title, content, accessLevel: req.accessLevel });
  }
);

app.put('/api/documents/:id',
  authenticateUser,
  documentLimiter,
  requireDocumentAccess(AccessLevel.WRITE),
  async (req, res) => {
    // Only users with WRITE access reach here
    const { title, content } = req.body;

    await pool.query(
      'UPDATE documents SET title = $1, content = $2, updated_at = NOW() WHERE id = $3',
      [title, content, req.params.id]
    );

    auditLogger.info({
      event: 'document_updated',
      userId: req.user.id,
      documentId: req.params.id,
      timestamp: new Date().toISOString()
    });

    res.json({ success: true });
  }
);

app.delete('/api/documents/:id',
  authenticateUser,
  requireDocumentAccess(AccessLevel.ADMIN),
  async (req, res) => {
    // Only owners reach here
    await pool.query('DELETE FROM documents WHERE id = $1', [req.params.id]);

    auditLogger.info({
      event: 'document_deleted',
      userId: req.user.id,
      documentId: req.params.id,
      timestamp: new Date().toISOString()
    });

    res.json({ success: true });
  }
);

function authenticateUser(req, res, next) {
  // JWT validation implementation
  req.user = { id: 'user-uuid-here', role: 'user' };
  next();
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT validation ensures identity before any authorization check
```javascript
function authenticateUser(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  // Verify and decode JWT
}
```

2. **Authorization Layer**: Multi-path permission checking (owner → direct → team → public)
```javascript
// Check all access paths in single query for performance
const accessResult = await authService.checkAccess(userId, documentId, requiredLevel);
```

3. **Input Validation Layer**: UUID format validation prevents enumeration and injection
```javascript
if (!uuidRegex.test(documentId)) {
  return res.status(400).json({ error: 'Invalid document ID' });
}
```

**Additional Protections**:
- **Rate limiting**: Prevents brute-force enumeration attempts (100 requests/15 minutes)
- **Consistent error responses**: 404 for both "not found" and "no access" prevents information leakage
- **Comprehensive audit logging**: Every access attempt is logged with user, document, IP, and timestamp for forensics
- **Principle of least privilege**: Access levels (READ/WRITE/ADMIN) ensure users only get minimum required permissions
- **Security headers**: Helmet.js adds CSP, X-Frame-Options, etc. to prevent client-side attacks

Your question touches on one of the most common and dangerous vulnerabilities: forced browsing (also known as Insecure Direct Object Reference or IDOR). This occurs when applications expose internal object references in URLs without proper authorization checks, allowing attackers to access resources belonging to other users simply by guessing or incrementing IDs.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import java.nio.file.Path;
import java.nio.file.Paths;

@RestController
@RequestMapping("/api")
public class DocumentController {

    private static final String DOCUMENT_STORAGE = "/var/app/documents/";

    // VULNERABLE: No authorization check - any user can access any document
    @GetMapping("/documents/{documentId}")
    public ResponseEntity<Resource> downloadDocument(
            @PathVariable Long documentId) {
        try {
            // Directly uses user-supplied documentId without ownership verification
            Document doc = documentRepository.findById(documentId)
                    .orElseThrow(() -> new ResourceNotFoundException("Document not found"));

            Path filePath = Paths.get(DOCUMENT_STORAGE).resolve(doc.getFilename());
            Resource resource = new UrlResource(filePath.toUri());

            return ResponseEntity.ok()
                    .header("Content-Disposition", 
                            "attachment; filename=\"" + doc.getFilename() + "\"")
                    .body(resource);
        } catch (Exception e) {
            return ResponseEntity.notFound().build();
        }
    }

    // VULNERABLE: Sequential ID exposure in listing
    @GetMapping("/documents")
    public ResponseEntity<List<DocumentDTO>> listAllDocuments() {
        // Returns all documents with their IDs - information disclosure
        return ResponseEntity.ok(documentRepository.findAll().stream()
                .map(this::toDTO)
                .collect(Collectors.toList()));
    }
}
```

**Attack Payload**:
```bash
# Attacker iterates through document IDs to steal other users' files
for id in $(seq 1 100000); do
    curl -s "https://vulnerable-app.com/api/documents/$id" -o "stolen_doc_$id.pdf"
    sleep 0.1
done

# Or using Burp Suite Intruder with sequential payload
# GET /api/documents/§1§ HTTP/1.1
# Payload: Numbers 1-100000
```

**Why This Is Dangerous**:
- No ownership verification - any authenticated user can access ANY document by guessing IDs
- Sequential/predictable IDs make enumeration trivial (First American had 885M+ sequential records)
- No rate limiting allows mass automated scraping
- Sensitive documents (financial records, SSNs, medical records) exposed to unauthorized access
- Violates principle of least privilege and data protection regulations (GDPR, CCPA, HIPAA)

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.access.AccessDeniedException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;

@RestController
@RequestMapping("/api")
public class SecureDocumentController {

    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");
    private static final String DOCUMENT_STORAGE = "/var/app/documents/";

    private final DocumentRepository documentRepository;
    private final DocumentAuthorizationService authService;

    public SecureDocumentController(DocumentRepository documentRepository,
                                     DocumentAuthorizationService authService) {
        this.documentRepository = documentRepository;
        this.authService = authService;
    }

    @GetMapping("/documents/{documentUuid}")
    public ResponseEntity<Resource> downloadDocument(
            @PathVariable UUID documentUuid,
            @AuthenticationPrincipal UserPrincipal currentUser) {

        // SECURITY: Use non-guessable UUID instead of sequential ID
        Document doc = documentRepository.findByUuid(documentUuid)
                .orElseThrow(() -> {
                    auditLog.warn("Document access attempt for non-existent UUID={} by user={}",
                            documentUuid, currentUser.getId());
                    // Return generic error - don't reveal if document exists
                    return new ResourceNotFoundException("Resource not found");
                });

        // CRITICAL: Verify the current user owns or has access to this document
        if (!authService.canAccessDocument(currentUser, doc)) {
            auditLog.warn("UNAUTHORIZED_ACCESS_ATTEMPT: user={} attempted to access document={} owned by={}",
                    currentUser.getId(), documentUuid, doc.getOwnerId());
            throw new AccessDeniedException("Access denied");
        }

        try {
            // Validate filename to prevent path traversal
            String sanitizedFilename = Paths.get(doc.getFilename()).getFileName().toString();
            Path filePath = Paths.get(DOCUMENT_STORAGE).resolve(sanitizedFilename).normalize();

            // Ensure file is within allowed directory
            if (!filePath.startsWith(DOCUMENT_STORAGE)) {
                auditLog.error("PATH_TRAVERSAL_ATTEMPT: user={} filename={}",
                        currentUser.getId(), doc.getFilename());
                throw new AccessDeniedException("Invalid file path");
            }

            Resource resource = new UrlResource(filePath.toUri());

            auditLog.info("DOCUMENT_DOWNLOADED: user={} document={} filename={}",
                    currentUser.getId(), documentUuid, sanitizedFilename);

            return ResponseEntity.ok()
                    .header("Content-Disposition", 
                            "attachment; filename=\"" + sanitizedFilename + "\"")
                    .body(resource);
        } catch (Exception e) {
            auditLog.error("Document download failed: {}", e.getMessage());
            return ResponseEntity.internalServerError().build();
        }
    }

    // SECURE: Only return documents owned by the current user
    @GetMapping("/documents")
    public ResponseEntity<List<DocumentDTO>> listUserDocuments(
            @AuthenticationPrincipal UserPrincipal currentUser) {
        List<Document> userDocs = documentRepository.findByOwnerId(currentUser.getId());
        return ResponseEntity.ok(userDocs.stream()
                .map(this::toDTO)
                .collect(Collectors.toList()));
    }
}
```

**Key Security Controls**:
- **Ownership verification**: Every request checks if the authenticated user owns or has explicit access to the requested resource
- **UUID instead of sequential IDs**: Makes enumeration attacks computationally infeasible (2^128 possibilities vs sequential guessing)
- **Audit logging**: All access attempts logged for forensic analysis and anomaly detection
- **Consistent error responses**: Returns same error for "not found" and "not authorized" to prevent information leakage
- **Path traversal prevention**: Validates and normalizes file paths to prevent directory escape attacks

Excellent question! Real-world applications require complex authorization models where documents can be shared with individuals, groups, or made public, while also supporting admin override capabilities. This requires a robust permission system with proper audit trails.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.transaction.annotation.Transactional;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.Bandwidth;
import java.time.Duration;
import java.util.*;

@RestController
@RequestMapping("/api/v2/documents")
public class ProductionDocumentController {

    private static final Logger auditLog = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final Logger appLog = LoggerFactory.getLogger(ProductionDocumentController.class);

    private final DocumentRepository documentRepository;
    private final DocumentPermissionService permissionService;
    private final DocumentAccessLogRepository accessLogRepository;
    private final RateLimiterService rateLimiter;
    private final SecurityEventPublisher securityEvents;

    // Permission levels for granular access control
    public enum PermissionLevel {
        NONE(0),
        VIEW(1),
        DOWNLOAD(2),
        EDIT(3),
        SHARE(4),
        OWNER(5),
        ADMIN(10);

        private final int level;
        PermissionLevel(int level) { this.level = level; }
        public boolean canPerform(PermissionLevel required) {
            return this.level >= required.level;
        }
    }

    @GetMapping("/{documentUuid}")
    @Transactional(readOnly = true)
    public ResponseEntity<Resource> downloadDocument(
            @PathVariable UUID documentUuid,
            @AuthenticationPrincipal UserPrincipal currentUser,
            HttpServletRequest request) {

        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        // LAYER 1: Rate limiting per user
        if (!rateLimiter.tryConsume(currentUser.getId(), "document_download")) {
            auditLog.warn("RATE_LIMIT_EXCEEDED: requestId={} user={} ip={} endpoint=document_download",
                    requestId, currentUser.getId(), clientIp);
            securityEvents.publish(new RateLimitExceededEvent(currentUser.getId(), "document_download"));
            return ResponseEntity.status(429)
                    .header("Retry-After", "60")
                    .build();
        }

        // LAYER 2: Fetch document with defensive null handling
        Optional<Document> docOptional = documentRepository.findByUuid(documentUuid);
        if (docOptional.isEmpty()) {
            logAccessAttempt(requestId, currentUser, documentUuid, "NOT_FOUND", clientIp);
            // Consistent timing to prevent timing attacks
            performDummyAuthCheck();
            return ResponseEntity.notFound().build();
        }

        Document doc = docOptional.get();

        // LAYER 3: Multi-factor authorization check
        AuthorizationResult authResult = performAuthorizationCheck(currentUser, doc, PermissionLevel.DOWNLOAD);

        if (!authResult.isAuthorized()) {
            logAccessAttempt(requestId, currentUser, documentUuid, 
                    "DENIED:" + authResult.getReason(), clientIp);

            // Detect potential enumeration attack
            if (isEnumerationAttackSuspected(currentUser.getId())) {
                securityEvents.publish(new SuspiciousActivityEvent(
                        currentUser.getId(), "POTENTIAL_ENUMERATION_ATTACK", clientIp));
            }

            // Return 404 instead of 403 to prevent information leakage
            return ResponseEntity.notFound().build();
        }

        // LAYER 4: Additional checks for sensitive documents
        if (doc.getClassification() == Classification.CONFIDENTIAL) {
            if (!verifyEnhancedAuthorization(currentUser, doc)) {
                auditLog.warn("CONFIDENTIAL_ACCESS_DENIED: requestId={} user={} doc={}",
                        requestId, currentUser.getId(), documentUuid);
                return ResponseEntity.notFound().build();
            }
        }

        // LAYER 5: Serve the document
        try {
            Resource resource = loadDocumentSecurely(doc);

            // Log successful access
            logAccessAttempt(requestId, currentUser, documentUuid, "SUCCESS", clientIp);
            recordAccessLog(currentUser, doc, "DOWNLOAD", clientIp, authResult.getAccessPath());

            return ResponseEntity.ok()
                    .header("Content-Disposition", 
                            "attachment; filename=\"" + sanitizeFilename(doc.getFilename()) + "\"")
                    .header("X-Request-Id", requestId)
                    .header("Cache-Control", "no-store, no-cache, must-revalidate")
                    .header("Pragma", "no-cache")
                    .body(resource);
        } catch (Exception e) {
            appLog.error("Document retrieval failed: requestId={} error={}", requestId, e.getMessage());
            return ResponseEntity.internalServerError().build();
        }
    }

    /**
     * Multi-path authorization check supporting:
     * - Direct ownership
     * - Explicit user share
     * - Group membership
     * - Organization-wide access
     * - Admin override (with audit trail)
     */
    private AuthorizationResult performAuthorizationCheck(
            UserPrincipal user, Document doc, PermissionLevel required) {

        // Path 1: Owner always has full access
        if (doc.getOwnerId().equals(user.getId())) {
            return AuthorizationResult.authorized("OWNER");
        }

        // Path 2: Check explicit user permissions
        Optional<DocumentPermission> userPermission = 
                permissionService.getUserPermission(doc.getId(), user.getId());
        if (userPermission.isPresent() && 
            userPermission.get().getLevel().canPerform(required)) {
            return AuthorizationResult.authorized("DIRECT_SHARE");
        }

        // Path 3: Check group-based permissions
        Set<Long> userGroups = user.getGroupIds();
        Optional<DocumentPermission> groupPermission = 
                permissionService.getHighestGroupPermission(doc.getId(), userGroups);
        if (groupPermission.isPresent() && 
            groupPermission.get().getLevel().canPerform(required)) {
            return AuthorizationResult.authorized("GROUP:" + groupPermission.get().getGroupId());
        }

        // Path 4: Check organization-wide policies
        if (doc.getVisibility() == Visibility.ORGANIZATION &&
            user.getOrganizationId().equals(doc.getOrganizationId()) &&
            PermissionLevel.VIEW.canPerform(required)) {
            return AuthorizationResult.authorized("ORGANIZATION_VISIBLE");
        }

        // Path 5: Admin access with elevated logging
        if (user.hasRole("ROLE_ADMIN") || user.hasRole("ROLE_DOCUMENT_ADMIN")) {
            // Admin access requires explicit justification in production
            auditLog.info("ADMIN_ACCESS: user={} accessed doc={} owned_by={}",
                    user.getId(), doc.getUuid(), doc.getOwnerId());
            securityEvents.publish(new AdminAccessEvent(user.getId(), doc.getUuid()));
            return AuthorizationResult.authorized("ADMIN_OVERRIDE");
        }

        return AuthorizationResult.denied("NO_PERMISSION");
    }

    /**
     * Share document with another user - with permission validation
     */
    @PostMapping("/{documentUuid}/share")
    @Transactional
    public ResponseEntity<ShareResult> shareDocument(
            @PathVariable UUID documentUuid,
            @RequestBody @Valid ShareRequest request,
            @AuthenticationPrincipal UserPrincipal currentUser) {

        Document doc = documentRepository.findByUuid(documentUuid)
                .orElseThrow(() -> new ResourceNotFoundException("Document not found"));

        // User must have SHARE permission or be owner to share
        AuthorizationResult authResult = performAuthorizationCheck(
                currentUser, doc, PermissionLevel.SHARE);

        if (!authResult.isAuthorized()) {
            return ResponseEntity.status(403).build();
        }

        // Cannot grant higher permissions than you have
        PermissionLevel currentUserLevel = permissionService
                .getEffectivePermission(doc.getId(), currentUser.getId());

        if (request.getPermissionLevel().level > currentUserLevel.level) {
            auditLog.warn("PRIVILEGE_ESCALATION_ATTEMPT: user={} tried to grant {} but only has {}",
                    currentUser.getId(), request.getPermissionLevel(), currentUserLevel);
            return ResponseEntity.badRequest()
                    .body(new ShareResult(false, "Cannot grant permissions higher than your own"));
        }

        // Create the share
        permissionService.createShare(doc.getId(), request.getTargetUserId(), 
                request.getPermissionLevel(), currentUser.getId());

        auditLog.info("DOCUMENT_SHARED: doc={} shared_by={} to={} level={}",
                documentUuid, currentUser.getId(), request.getTargetUserId(), 
                request.getPermissionLevel());

        return ResponseEntity.ok(new ShareResult(true, "Document shared successfully"));
    }

    // Detect enumeration attacks by tracking access patterns
    private boolean isEnumerationAttackSuspected(Long userId) {
        long recentFailures = accessLogRepository
                .countFailedAccessInWindow(userId, Duration.ofMinutes(5));
        return recentFailures > 10; // Threshold for suspicion
    }

    private void performDummyAuthCheck() {
