@Service
public class RateLimiterService {
    private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

    public boolean tryConsume(Long userId, String operation) {
        String key = userId + ":" + operation;
        Bucket bucket = buckets.computeIfAbsent(key, k -> createBucket(operation));
        return bucket.tryConsume(1);
    }

    private Bucket createBucket(String operation) {
        Bandwidth limit = switch (operation) {
            case "document_download" -> Bandwidth.classic(100, Refill.intervally(100, Duration.ofHours(1)));
            case "document_list" -> Bandwidth.classic(1000, Refill.intervally(1000, Duration.ofHours(1)));
            default -> Bandwidth.classic(500, Refill.intervally(500, Duration.ofHours(1)));
        };
        return Bucket.builder().addLimit(limit).build();
    }
}
