		authUser, err := validateTokenAndGetUser(token)
		if err != nil {
			http.Error(w, "Invalid token", http.StatusUnauthorized)
			return
		}

		ctx := context.WithValue(r.Context(), userContextKey, authUser)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// SECURE: Authorization check ensures users can only access their own data
func GetUserProfile(w http.ResponseWriter, r *http.Request) {
	// Get authenticated user from context
	authUser, ok := r.Context().Value(userContextKey).(*AuthenticatedUser)
	if !ok {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	vars := mux.Vars(r)
	requestedID, err := strconv.Atoi(vars["id"])
	if err != nil {
