		return
	}

	// AUTHORIZATION CHECK: User can only access their own profile
	// Admins can access any profile
	if authUser.ID != requestedID && authUser.Role != "admin" {
		log.Printf("SECURITY: User %d attempted to access user %d profile", authUser.ID, requestedID)
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
