**Key Security Controls**:
- **Authentication Middleware**: Every request must include valid JWT token before accessing protected endpoints
- **Authorization Check**: Compares authenticated user's ID against requested resource ID - users can only access their own data
- **Role-Based Bypass**: Only admin users can access other users' profiles, with proper audit logging
- **Security Logging**: Failed authorization attempts are logged for security monitoring

For complex authorization scenarios, you need a centralized authorization service with explicit permission checks. This prevents scattered authorization logic that's easy to miss.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/google/uuid"
	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

// Permission constants - use UUIDs for resource IDs to prevent enumeration
const (
	PermissionRead   = "read"
	PermissionWrite  = "write"
	PermissionDelete = "delete"
	PermissionShare  = "share"
)

type AuthenticatedUser struct {
	ID    string
	Role  string
	OrgID string
}

type Document struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Content   string    `json:"content"`
	OwnerID   string    `json:"owner_id"`
	CreatedAt time.Time `json:"created_at"`
}

// Centralized Authorization Service
type AuthzService struct {
	db *sql.DB
}

func NewAuthzService(db *sql.DB) *AuthzService {
	return &AuthzService{db: db}
}

// CheckPermission verifies if user has specific permission on resource
func (a *AuthzService) CheckPermission(ctx context.Context, userID, resourceType, resourceID, permission string) (bool, error) {
	// Check 1: Is user the owner?
	var ownerID string
	query := fmt.Sprintf("SELECT owner_id FROM %s WHERE id = $1", sanitizeTableName(resourceType))
	err := a.db.QueryRowContext(ctx, query, resourceID).Scan(&ownerID)
	if err == sql.ErrNoRows {
		return false, nil // Resource doesn't exist
	}
	if err != nil {
		return false, err
	}

	if ownerID == userID {
		return true, nil // Owner has all permissions
	}

	// Check 2: Explicit permission grant in access control table
	var count int
	err = a.db.QueryRowContext(ctx, `
		SELECT COUNT(*) FROM resource_permissions 
		WHERE resource_type = $1 
		AND resource_id = $2 
		AND user_id = $3 
		AND permission = $4
		AND (expires_at IS NULL OR expires_at > NOW())`,
		resourceType, resourceID, userID, permission,
	).Scan(&count)

	if err != nil {
		return false, err
	}

	return count > 0, nil
}

// GrantPermission creates an explicit permission grant
func (a *AuthzService) GrantPermission(ctx context.Context, granterID, granteeID, resourceType, resourceID, permission string, expiresAt *time.Time) error {
	// Verify granter has share permission
	canShare, err := a.CheckPermission(ctx, granterID, resourceType, resourceID, PermissionShare)
	if err != nil || !canShare {
		return fmt.Errorf("permission denied: cannot share resource")
	}

	_, err = a.db.ExecContext(ctx, `
		INSERT INTO resource_permissions (id, resource_type, resource_id, user_id, permission, granted_by, expires_at, created_at)
		VALUES ($1, $2, $3, $4, $5, $6, $7, NOW())
		ON CONFLICT (resource_type, resource_id, user_id, permission) DO UPDATE SET expires_at = $7`,
		uuid.New().String(), resourceType, resourceID, granteeID, permission, granterID, expiresAt,
	)

	return err
}

// Whitelist of valid table names to prevent SQL injection
func sanitizeTableName(name string) string {
	allowed := map[string]string{
		"documents": "documents",
		"projects":  "projects",
		"reports":   "reports",
	}
	if tableName, ok := allowed[name]; ok {
		return tableName
	}
	return ""
}

// Authorization middleware that wraps handlers
type AuthzMiddleware struct {
	authz *AuthzService
}

func (m *AuthzMiddleware) RequirePermission(resourceType, permission string, idParam string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			user := r.Context().Value("user").(*AuthenticatedUser)
			vars := mux.Vars(r)
			resourceID := vars[idParam]

			// Validate UUID format to prevent enumeration
			if _, err := uuid.Parse(resourceID); err != nil {
				logSecurityEvent(r, user.ID, "INVALID_RESOURCE_ID", resourceType, resourceID)
				http.Error(w, "Invalid resource ID", http.StatusBadRequest)
				return
			}

			hasPermission, err := m.authz.CheckPermission(r.Context(), user.ID, resourceType, resourceID, permission)
			if err != nil {
				log.Printf("Authorization error: %v", err)
				http.Error(w, "Internal server error", http.StatusInternalServerError)
				return
			}

			if !hasPermission {
				logSecurityEvent(r, user.ID, "AUTHZ_DENIED", resourceType, resourceID)
				// Return 404 instead of 403 to prevent resource enumeration
				http.Error(w, "Not found", http.StatusNotFound)
				return
			}

			logSecurityEvent(r, user.ID, "AUTHZ_GRANTED", resourceType, resourceID)
			next.ServeHTTP(w, r)
		})
	}
}

// Security event logging for monitoring and alerting
func logSecurityEvent(r *http.Request, userID, event, resourceType, resourceID string) {
	log.Printf("SECURITY_EVENT: event=%s user=%s resource_type=%s resource_id=%s ip=%s user_agent=%s",
		event, userID, resourceType, resourceID, r.RemoteAddr, r.UserAgent())
}

// Document handlers with authorization
type DocumentHandler struct {
	db    *sql.DB
	authz *AuthzService
}

func (h *DocumentHandler) GetDocument(w http.ResponseWriter, r *http.Request) {
	// Authorization already verified by middleware
	vars := mux.Vars(r)
	docID := vars["id"]

	var doc Document
	err := h.db.QueryRowContext(r.Context(),
		"SELECT id, title, content, owner_id, created_at FROM documents WHERE id = $1",
		docID,
	).Scan(&doc.ID, &doc.Title, &doc.Content, &doc.OwnerID, &doc.CreatedAt)

	if err == sql.ErrNoRows {
		http.Error(w, "Not found", http.StatusNotFound)
		return
	}
	if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Cache-Control", "private, no-store")
	json.NewEncoder(w).Encode(doc)
}

func (h *DocumentHandler) ShareDocument(w http.ResponseWriter, r *http.Request) {
	user := r.Context().Value("user").(*AuthenticatedUser)
	vars := mux.Vars(r)
	docID := vars["id"]

	var req struct {
		UserID     string     `json:"user_id"`
		Permission string     `json:"permission"`
		ExpiresAt  *time.Time `json:"expires_at,omitempty"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate permission value
	allowedPerms := map[string]bool{PermissionRead: true, PermissionWrite: true}
	if !allowedPerms[req.Permission] {
		http.Error(w, "Invalid permission", http.StatusBadRequest)
		return
	}

	err := h.authz.GrantPermission(r.Context(), user.ID, req.UserID, "documents", docID, req.Permission, req.ExpiresAt)
	if err != nil {
		log.Printf("Share error: %v", err)
		http.Error(w, "Failed to share document", http.StatusForbidden)
		return
	}

	logSecurityEvent(r, user.ID, "PERMISSION_GRANTED", "documents", docID)
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "shared"})
}

func main() {
	db, _ := sql.Open("postgres", "postgres://localhost/myapp?sslmode=require")
	authzService := NewAuthzService(db)
	authzMiddleware := &AuthzMiddleware{authz: authzService}
	docHandler := &DocumentHandler{db: db, authz: authzService}

	r := mux.NewRouter()
	api := r.PathPrefix("/api").Subrouter()
	// api.Use(AuthMiddleware) // JWT validation middleware

	// Document routes with authorization
	api.Handle("/documents/{id}",
		authzMiddleware.RequirePermission("documents", PermissionRead, "id")(
			http.HandlerFunc(docHandler.GetDocument),
		),
	).Methods("GET")

	api.Handle("/documents/{id}/share",
		authzMiddleware.RequirePermission("documents", PermissionShare, "id")(
			http.HandlerFunc(docHandler.ShareDocument),
		),
	).Methods("POST")

	log.Fatal(http.ListenAndServe(":8080", r))
}
```

