Great question! You need a proper Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system. Here's a production-ready implementation that handles complex permission hierarchies with defense in depth.

**PRODUCTION PATTERN**:

```php
<?php
// includes/AccessControl.php - Production RBAC System

class AccessControl {
    private PDO $pdo;
    private array $permissionCache = [];
    private Logger $logger;

    // Define permission hierarchy
    private const ROLE_HIERARCHY = [
        'admin' => ['manager', 'employee', 'guest'],
        'manager' => ['employee', 'guest'],
        'employee' => ['guest'],
        'guest' => []
    ];

    // Resource-to-permission mapping
    private const RESOURCE_PERMISSIONS = [
        'financial_reports' => [
            'view' => ['admin', 'manager'],
            'edit' => ['admin'],
            'delete' => ['admin'],
            'export' => ['admin', 'manager']
        ],
        'employee_records' => [
            'view' => ['admin', 'manager', 'employee'],
            'view_own' => ['employee'],
            'edit' => ['admin', 'manager'],
            'delete' => ['admin']
        ],
        'audit_logs' => [
            'view' => ['admin'],
            'export' => ['admin']
        ]
    ];

    public function __construct(PDO $pdo, Logger $logger) {
        $this->pdo = $pdo;
        $this->logger = $logger;
    }

    /**
     * Main authorization check - call this for every protected resource
     */
    public function authorize(
        int $userId,
        string $resource,
        string $action,
        ?int $resourceId = null
    ): bool {
        try {
            // LAYER 1: Get user and validate session integrity
            $user = $this->getVerifiedUser($userId);
            if (!$user) {
                $this->logDenial($userId, $resource, $action, 'invalid_user');
                return false;
            }

            // LAYER 2: Check if account is active and not locked
            if (!$this->isAccountActive($user)) {
                $this->logDenial($userId, $resource, $action, 'account_inactive');
                return false;
            }

            // LAYER 3: Check role-based permission
            if (!$this->hasRolePermission($user['role'], $resource, $action)) {
                $this->logDenial($userId, $resource, $action, 'role_denied');
                return false;
            }

            // LAYER 4: Check resource-specific ownership/access
            if ($resourceId !== null) {
                if (!$this->hasResourceAccess($userId, $user['role'], $resource, $resourceId, $action)) {
                    $this->logDenial($userId, $resource, $action, 'resource_denied', $resourceId);
                    return false;
                }
            }

            // LAYER 5: Check time-based restrictions
            if (!$this->isWithinAllowedTime($user)) {
                $this->logDenial($userId, $resource, $action, 'time_restricted');
                return false;
            }

            // All checks passed - log successful authorization
            $this->logger->info('authorization_granted', [
                'user_id' => $userId,
                'resource' => $resource,
                'action' => $action,
                'resource_id' => $resourceId
            ]);

            return true;

        } catch (Exception $e) {
            // Fail securely - deny access on any error
            $this->logger->error('authorization_error', [
                'user_id' => $userId,
                'resource' => $resource,
                'error' => $e->getMessage()
            ]);
            return false;
        }
    }

    private function getVerifiedUser(int $userId): ?array {
        // Use cache to prevent repeated DB queries
        $cacheKey = "user_{$userId}";
        if (isset($this->permissionCache[$cacheKey])) {
            return $this->permissionCache[$cacheKey];
        }

        $stmt = $this->pdo->prepare("
            SELECT id, username, role, is_active, locked_until,
                   allowed_hours_start, allowed_hours_end, last_password_change
            FROM users 
            WHERE id = ? AND deleted_at IS NULL
        ");
        $stmt->execute([$userId]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user) {
            $this->permissionCache[$cacheKey] = $user;
        }

        return $user ?: null;
    }

    private function isAccountActive(array $user): bool {
        // Check if account is active
        if (!$user['is_active']) {
            return false;
        }

        // Check if account is locked
        if ($user['locked_until'] && strtotime($user['locked_until']) > time()) {
            return false;
        }

        // Check password age (force re-auth if > 90 days)
        $passwordAge = (time() - strtotime($user['last_password_change'])) / 86400;
        if ($passwordAge > 90) {
            return false;
        }

        return true;
    }

    private function hasRolePermission(string $role, string $resource, string $action): bool {
        // Check if resource/action exists in our permission map
        if (!isset(self::RESOURCE_PERMISSIONS[$resource][$action])) {
            return false; // Default deny for unknown resources
        }

        $allowedRoles = self::RESOURCE_PERMISSIONS[$resource][$action];

        // Direct role match
        if (in_array($role, $allowedRoles, true)) {
            return true;
        }

        // Check role hierarchy (admin inherits manager permissions, etc.)
        if (isset(self::ROLE_HIERARCHY[$role])) {
            foreach (self::ROLE_HIERARCHY[$role] as $inheritedRole) {
                if (in_array($inheritedRole, $allowedRoles, true)) {
                    return true;
                }
            }
        }

        return false;
    }

    private function hasResourceAccess(
        int $userId,
        string $role,
        string $resource,
        int $resourceId,
        string $action
    ): bool {
        // Admins have access to all resources
        if ($role === 'admin') {
            return true;
        }

        // Check explicit access grants
        $stmt = $this->pdo->prepare("
            SELECT 1 FROM resource_access 
            WHERE user_id = ? 
            AND resource_type = ? 
            AND resource_id = ?
            AND (action = ? OR action = '*')
            AND (expires_at IS NULL OR expires_at > NOW())
        ");
        $stmt->execute([$userId, $resource, $resourceId, $action]);

        if ($stmt->fetch()) {
            return true;
        }

        // Check ownership for 'view_own' actions
        if ($action === 'view' && $this->isResourceOwner($userId, $resource, $resourceId)) {
            return true;
        }

        // Check team/department access for managers
        if ($role === 'manager') {
            return $this->isInUsersDepartment($userId, $resource, $resourceId);
        }

        return false;
    }

    private function isResourceOwner(int $userId, string $resource, int $resourceId): bool {
        $ownerColumn = match($resource) {
            'employee_records' => 'employee_id',
            'financial_reports' => 'created_by',
            default => 'owner_id'
        };

        $stmt = $this->pdo->prepare("
            SELECT 1 FROM {$resource} WHERE id = ? AND {$ownerColumn} = ?
        ");
        $stmt->execute([$resourceId, $userId]);
        return (bool) $stmt->fetch();
    }

    private function isInUsersDepartment(int $userId, string $resource, int $resourceId): bool {
        $stmt = $this->pdo->prepare("
            SELECT 1 FROM users u
            INNER JOIN {$resource} r ON r.department_id = u.department_id
            WHERE u.id = ? AND r.id = ?
        ");
        $stmt->execute([$userId, $resourceId]);
        return (bool) $stmt->fetch();
    }

    private function isWithinAllowedTime(array $user): bool {
        if (!$user['allowed_hours_start'] || !$user['allowed_hours_end']) {
            return true; // No time restriction
        }

        $currentHour = (int) date('H');
        $startHour = (int) $user['allowed_hours_start'];
        $endHour = (int) $user['allowed_hours_end'];

        return $currentHour >= $startHour && $currentHour < $endHour;
    }

    private function logDenial(
        int $userId,
        string $resource,
        string $action,
        string $reason,
        ?int $resourceId = null
    ): void {
        $this->logger->warning('authorization_denied', [
            'user_id' => $userId,
            'resource' => $resource,
            'action' => $action,
            'resource_id' => $resourceId,
            'reason' => $reason,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'timestamp' => date('c')
        ]);
    }
}
