namespace InvoiceApp
{
    public static class AuthorizationConfig
    {
        public static void ConfigureAuthorization(IServiceCollection services)
        {
            services.AddScoped<IAuthorizationHandler, InvoiceAuthorizationHandler>();

            services.AddAuthorization(options =>
            {
                options.AddPolicy("RequireInvoiceManagement", policy =>
                    policy.RequireClaim("permission", "invoices:read:all"));

                options.AddPolicy("RequireInvoiceOwnership", policy =>
                    policy.Requirements.Add(new ResourceOwnerRequirement(
                        allowSharedAccess: false,
                        allowAdminAccess: false)));
            });
        }
    }
}
