```csharp
// Reusable authorization check across all controllers
public interface IResourceAuthorizationService
{
    Task<bool> CanAccessAsync<T>(ClaimsPrincipal user, T resource) where T : IOwnedResource;
}

public class ResourceAuthorizationService : IResourceAuthorizationService
{
    public async Task<bool> CanAccessAsync<T>(ClaimsPrincipal user, T resource) 
        where T : IOwnedResource
    {
        var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
        return resource.OwnerId == userId || user.IsInRole("Admin");
    }
}
