from flask import Flask, request, abort, g, session
from functools import wraps
from enum import Enum, auto
from dataclasses import dataclass
from typing import Optional, Set, Callable
import logging
from datetime import datetime
import hashlib

app = Flask(__name__)

# Security audit logger with structured logging
audit_logger = logging.getLogger('security.audit')
audit_logger.setLevel(logging.INFO)

class Permission(Enum):
    """Fine-grained permissions for the application."""
    # User management
    USERS_VIEW = auto()
    USERS_CREATE = auto()
    USERS_UPDATE = auto()
    USERS_DELETE = auto()

    # Department-scoped permissions
    DEPT_USERS_VIEW = auto()
    DEPT_USERS_MANAGE = auto()

    # System administration
    SYSTEM_CONFIG = auto()
    AUDIT_LOGS_VIEW = auto()

    # Reports
    REPORTS_VIEW = auto()
    REPORTS_EXPORT = auto()

@dataclass
class Role:
    """Role with associated permissions."""
    name: str
    permissions: Set[Permission]
    department_scoped: bool = False

# Define roles with specific permission sets
ROLES = {
    'super_admin': Role(
        name='super_admin',
        permissions=set(Permission),  # All permissions
        department_scoped=False
    ),
    'user_admin': Role(
        name='user_admin',
        permissions={
            Permission.USERS_VIEW,
            Permission.USERS_CREATE,
            Permission.USERS_UPDATE,
            # Note: No USERS_DELETE - can't delete users
        },
        department_scoped=False
    ),
    'department_manager': Role(
        name='department_manager',
        permissions={
            Permission.DEPT_USERS_VIEW,
            Permission.DEPT_USERS_MANAGE,
            Permission.REPORTS_VIEW,
        },
        department_scoped=True  # Can only access own department
    ),
    'auditor': Role(
        name='auditor',
        permissions={
            Permission.USERS_VIEW,
            Permission.AUDIT_LOGS_VIEW,
            Permission.REPORTS_VIEW,
            Permission.REPORTS_EXPORT,
        },
        department_scoped=False
    ),
}

class AuthorizationError(Exception):
    """Custom exception for authorization failures."""
    def __init__(self, message: str, user_id: int, resource: str, action: str):
        self.message = message
        self.user_id = user_id
        self.resource = resource
        self.action = action
        super().__init__(self.message)

class AuthorizationService:
    """Centralized authorization service with audit logging."""

    @staticmethod
    def get_user_role(user) -> Optional[Role]:
        """Get the Role object for a user."""
        return ROLES.get(user.role_name)

    @staticmethod
    def has_permission(user, permission: Permission) -> bool:
        """Check if user has a specific permission."""
        role = AuthorizationService.get_user_role(user)
        if not role:
            return False
        return permission in role.permissions

    @staticmethod
    def can_access_resource(user, resource_owner_dept: str, permission: Permission) -> bool:
        """Check permission with department scope consideration."""
        role = AuthorizationService.get_user_role(user)
        if not role:
            return False

        if permission not in role.permissions:
            return False

        # If role is department-scoped, check department match
        if role.department_scoped:
            return user.department_id == resource_owner_dept

        return True

    @staticmethod
    def audit_log(user_id: int, action: str, resource: str, 
                  resource_id: str, success: bool, details: str = ""):
        """Log authorization decisions for audit trail."""
        log_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'user_id': user_id,
            'action': action,
            'resource': resource,
            'resource_id': resource_id,
            'success': success,
            'ip_address': request.remote_addr,
            'user_agent': request.headers.get('User-Agent', 'unknown')[:200],
            'request_id': g.get('request_id', 'unknown'),
            'details': details
        }

        if success:
            audit_logger.info(f"AUTHZ_SUCCESS: {log_entry}")
        else:
            audit_logger.warning(f"AUTHZ_FAILURE: {log_entry}")

def require_permission(*permissions: Permission):
    """Decorator factory for permission-based authorization."""
    def decorator(f: Callable):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user = get_current_user()

            if not user:
                AuthorizationService.audit_log(
                    user_id=0, action=f.__name__, resource=request.path,
                    resource_id='N/A', success=False, details='Unauthenticated'
                )
                abort(401)

            # Check if user has ANY of the required permissions
            has_perm = any(
                AuthorizationService.has_permission(user, perm) 
                for perm in permissions
            )

            if not has_perm:
                AuthorizationService.audit_log(
                    user_id=user.id, action=f.__name__, resource=request.path,
                    resource_id='N/A', success=False,
                    details=f'Missing permissions: {[p.name for p in permissions]}'
                )
                abort(403)

            # Store user in request context for the view
            g.current_user = user
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def require_resource_access(permission: Permission, get_resource_dept: Callable):
    """Decorator for resource-level authorization with department scoping."""
    def decorator(f: Callable):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user = get_current_user()

            if not user:
                abort(401)

            # Get the department of the resource being accessed
            resource_dept = get_resource_dept(*args, **kwargs)

            if not AuthorizationService.can_access_resource(user, resource_dept, permission):
                AuthorizationService.audit_log(
                    user_id=user.id, action=f.__name__, resource=request.path,
                    resource_id=str(kwargs), success=False,
                    details=f'Department mismatch or missing permission: {permission.name}'
                )
                abort(403)

            g.current_user = user
            return f(*args, **kwargs)
        return decorated_function
    return decorator

# Helper to get department from user ID
def get_user_department(user_id: int) -> str:
    """Retrieve the department of a user by their ID."""
    target_user = get_user_by_id(user_id)
    if not target_user:
        abort(404)
    return target_user.department_id

