Hiding admin links in the UI provides zero security protection. This is a classic "forced browsing" vulnerability where attackers simply guess or discover hidden URLs and access them directly. The server MUST verify authorization on EVERY request.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// VULNERABLE: No authorization check on admin routes
// Security through obscurity - just hiding links in UI

app.get('/admin/users', (req, res) => {
  // Anyone who knows this URL can access it!
  const users = db.query('SELECT * FROM users');
  res.json(users);
});

app.get('/admin/settings', (req, res) => {
  // No verification of admin privileges
  const settings = db.query('SELECT * FROM system_settings');
  res.json(settings);
});

app.delete('/admin/users/:id', (req, res) => {
  // Critical action with no authorization!
  db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
  res.json({ success: true });
});

app.get('/internal/reports/financial', (req, res) => {
  // Sensitive data exposed to anyone
  const reports = db.query('SELECT * FROM financial_reports');
  res.json(reports);
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker directly accesses admin endpoints
curl http://example.com/admin/users
curl http://example.com/admin/settings
curl -X DELETE http://example.com/admin/users/1
curl http://example.com/internal/reports/financial

# Directory enumeration to find hidden endpoints
ffuf -w /usr/share/wordlists/admin-paths.txt -u http://example.com/FUZZ
gobuster dir -u http://example.com -w /usr/share/wordlists/common.txt
```

**Why This Is Dangerous**:
- UI hiding is not a security control - attackers bypass the UI entirely
- No server-side verification allows any authenticated (or unauthenticated) user to access admin functions
- Predictable URL patterns (/admin/*, /internal/*) are easily guessable
- Sensitive data and destructive operations completely unprotected
- Automated tools can enumerate and discover hidden endpoints in seconds

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

const JWT_SECRET = process.env.JWT_SECRET;

// Middleware to verify JWT and extract user
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  jwt.verify(token, JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// SECURE: Authorization middleware that checks roles
const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    // Check if user has any of the allowed roles
    const hasRole = allowedRoles.some(role => req.user.roles.includes(role));

    if (!hasRole) {
      // Log unauthorized access attempt
      console.error(`Unauthorized access attempt: User ${req.user.id} tried to access ${req.path}`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

// Apply authentication to all admin routes
app.use('/admin', authenticateToken);

// SECURE: Admin routes with role verification
app.get('/admin/users', requireRole('admin', 'super_admin'), (req, res) => {
  const users = db.query('SELECT id, username, email, role FROM users');
  res.json(users);
});

app.get('/admin/settings', requireRole('admin', 'super_admin'), (req, res) => {
  const settings = db.query('SELECT * FROM system_settings');
  res.json(settings);
});

app.delete('/admin/users/:id', requireRole('super_admin'), (req, res) => {
  // Only super_admin can delete users
  db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **Server-side authorization on every request**: Each endpoint explicitly checks user roles before processing
- **Role-based access control (RBAC)**: Different actions require different privilege levels
- **Authentication before authorization**: User identity verified via JWT before role check
- **Logging of unauthorized attempts**: Failed access attempts are logged for security monitoring
- **Principle of least privilege**: Destructive actions (delete) require highest privilege level

Excellent question! This requires combining Role-Based Access Control (RBAC) with Resource-Based Access Control. You need to check both WHO the user is AND whether they own or have permission to access the specific resource.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');

const app = express();

// Security headers
app.use(helmet());

// Audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Rate limiting for sensitive endpoints
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests' },
  standardHeaders: true
});

// Permission definitions
const PERMISSIONS = {
  USERS_READ_OWN: 'users:read:own',
  USERS_READ_ALL: 'users:read:all',
  USERS_WRITE_OWN: 'users:write:own',
  USERS_WRITE_ALL: 'users:write:all',
  USERS_DELETE: 'users:delete',
  ADMIN_PANEL: 'admin:panel'
};

// Role to permissions mapping
const ROLE_PERMISSIONS = {
  user: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN
  ],
  moderator: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN,
    PERMISSIONS.USERS_READ_ALL
  ],
  admin: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN,
    PERMISSIONS.USERS_READ_ALL,
    PERMISSIONS.USERS_WRITE_ALL,
    PERMISSIONS.ADMIN_PANEL
  ],
  super_admin: Object.values(PERMISSIONS) // All permissions
};

// Get user permissions from role
const getUserPermissions = (role) => {
  return ROLE_PERMISSIONS[role] || [];
};

// Authentication middleware
const authenticate = async (req, res, next) => {
  try {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (!token) {
      auditLogger.warn({ event: 'auth_missing', ip: req.ip, path: req.path });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // Fetch fresh user data (don't trust JWT claims alone for permissions)
    const user = await db.query('SELECT id, role, is_active FROM users WHERE id = ?', [decoded.userId]);

    if (!user || !user.is_active) {
      auditLogger.warn({ event: 'auth_inactive_user', userId: decoded.userId });
      return res.status(403).json({ error: 'Account inactive' });
    }

    req.user = {
      id: user.id,
      role: user.role,
      permissions: getUserPermissions(user.role)
    };

    next();
  } catch (err) {
    auditLogger.warn({ event: 'auth_failed', error: err.message, ip: req.ip });
    return res.status(403).json({ error: 'Invalid token' });
  }
};

// Permission check middleware
const requirePermission = (permission) => {
  return (req, res, next) => {
    if (!req.user.permissions.includes(permission)) {
      auditLogger.warn({
        event: 'authorization_denied',
        userId: req.user.id,
        requiredPermission: permission,
        path: req.path,
        method: req.method
      });
      return res.status(403).json({ error: 'Permission denied' });
    }
    next();
  };
};

// Resource ownership check middleware
const checkResourceOwnership = (resourceType, paramName = 'id') => {
  return async (req, res, next) => {
    const resourceId = req.params[paramName];
    const userId = req.user.id;

    // Admins with write_all permission bypass ownership check
    if (req.user.permissions.includes(PERMISSIONS.USERS_WRITE_ALL)) {
      auditLogger.info({
        event: 'admin_resource_access',
        userId,
        resourceType,
        resourceId,
        path: req.path
      });
      return next();
    }

    // Check ownership based on resource type
    let isOwner = false;

    switch (resourceType) {
      case 'user':
        isOwner = parseInt(resourceId) === userId;
        break;
      case 'profile':
        const profile = await db.query('SELECT user_id FROM profiles WHERE id = ?', [resourceId]);
        isOwner = profile && profile.user_id === userId;
        break;
      case 'document':
        const doc = await db.query('SELECT owner_id FROM documents WHERE id = ?', [resourceId]);
        isOwner = doc && doc.owner_id === userId;
        break;
      default:
        return res.status(500).json({ error: 'Unknown resource type' });
    }

    if (!isOwner) {
      auditLogger.warn({
        event: 'ownership_violation',
        userId,
        resourceType,
        resourceId,
        path: req.path
      });
      return res.status(403).json({ error: 'Access denied to this resource' });
    }

    next();
  };
};

// Combined authorization: permission OR ownership
const authorizeAccess = (permission, resourceType, paramName = 'id') => {
  return async (req, res, next) => {
    // First check if user has broad permission
    if (req.user.permissions.includes(permission)) {
      return next();
    }

    // Otherwise, check resource ownership
    return checkResourceOwnership(resourceType, paramName)(req, res, next);
  };
};

// Routes
app.use(authenticate);
app.use('/admin', adminLimiter);

// Get user profile - own profile OR admin
app.get('/api/users/:id', 
  authorizeAccess(PERMISSIONS.USERS_READ_ALL, 'user'),
  async (req, res) => {
    const user = await db.query(
      'SELECT id, username, email, created_at FROM users WHERE id = ?', 
      [req.params.id]
    );

    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json(user);
  }
);

// Update user profile - own profile OR admin
app.put('/api/users/:id',
  authorizeAccess(PERMISSIONS.USERS_WRITE_ALL, 'user'),
  async (req, res) => {
    const { username, email } = req.body;
    const targetUserId = req.params.id;

    // Prevent privilege escalation - only super_admin can change roles
    if (req.body.role && !req.user.permissions.includes(PERMISSIONS.USERS_DELETE)) {
      auditLogger.warn({
        event: 'privilege_escalation_attempt',
        userId: req.user.id,
        targetUserId
      });
      return res.status(403).json({ error: 'Cannot modify user role' });
    }

    await db.query(
      'UPDATE users SET username = ?, email = ? WHERE id = ?',
      [username, email, targetUserId]
    );

    auditLogger.info({
      event: 'user_updated',
      actorId: req.user.id,
      targetUserId,
      changes: { username, email }
    });

    res.json({ success: true });
  }
);

// Delete user - admin only
app.delete('/api/users/:id',
  requirePermission(PERMISSIONS.USERS_DELETE),
  async (req, res) => {
    const targetUserId = req.params.id;

    // Prevent self-deletion
    if (parseInt(targetUserId) === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete own account' });
    }

    await db.query('UPDATE users SET is_active = false WHERE id = ?', [targetUserId]);

    auditLogger.info({
      event: 'user_deleted',
      actorId: req.user.id,
      targetUserId
    });

    res.json({ success: true });
  }
);

// Admin panel - admin permission required
app.get('/admin/dashboard',
  requirePermission(PERMISSIONS.ADMIN_PANEL),
  async (req, res) => {
    auditLogger.info({
      event: 'admin_panel_access',
      userId: req.user.id
    });

    const stats = await db.query('SELECT COUNT(*) as total_users FROM users');
    res.json(stats);
  }
);

app.listen(3000);
```

