**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.transaction.annotation.Transactional;
import io.github.bucket4j.Bandwidth;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.Refill;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@RestController
@RequestMapping("/api/v1/documents")
public class ProductionDocumentController {

    private final DocumentRepository documentRepository;
    private final DocumentPermissionRepository permissionRepository;
    private final AuditLogService auditLogService;
    private final DocumentAccessEvaluator accessEvaluator;
    private final AlertService alertService;

    // Rate limiting buckets per user
    private final Map<Long, Bucket> rateLimitBuckets = new ConcurrentHashMap<>();

    private static final String UPLOAD_DIR = "/secure/documents/";

    public ProductionDocumentController(
            DocumentRepository documentRepository,
            DocumentPermissionRepository permissionRepository,
            AuditLogService auditLogService,
            DocumentAccessEvaluator accessEvaluator,
            AlertService alertService) {
        this.documentRepository = documentRepository;
        this.permissionRepository = permissionRepository;
        this.auditLogService = auditLogService;
        this.accessEvaluator = accessEvaluator;
        this.alertService = alertService;
    }

    @GetMapping("/{documentUuid}")
    @Transactional(readOnly = true)
    public ResponseEntity<Resource> downloadDocument(
            @PathVariable UUID documentUuid,
            @AuthenticationPrincipal UserPrincipal currentUser,
            @RequestHeader(value = "X-Request-ID", required = false) String requestId) {

        String correlationId = requestId != null ? requestId : UUID.randomUUID().toString();

        // Layer 1: Rate limiting per user
        if (!checkRateLimit(currentUser.getId())) {
            auditLogService.logSecurityEvent(
                    SecurityEvent.RATE_LIMIT_EXCEEDED,
                    currentUser.getId(),
                    documentUuid.toString(),
                    correlationId);
            alertService.triggerAlert(AlertType.POTENTIAL_ENUMERATION, 
                    currentUser.getId(), "Rate limit exceeded");
            return ResponseEntity.status(429).build();
        }

        // Layer 2: Fetch document (UUID prevents enumeration)
        Optional<Document> docOpt = documentRepository.findByUuid(documentUuid);

        if (docOpt.isEmpty()) {
            // Constant-time response to prevent timing attacks
            auditLogService.logAccessAttempt(
                    currentUser.getId(),
                    documentUuid.toString(),
                    AccessResult.NOT_FOUND,
                    correlationId);
            return ResponseEntity.notFound().build();
        }

        Document doc = docOpt.get();

        // Layer 3: Multi-factor authorization check
        AccessDecision decision = accessEvaluator.evaluate(currentUser, doc);

        if (!decision.isAllowed()) {
            auditLogService.logAccessAttempt(
                    currentUser.getId(),
                    documentUuid.toString(),
                    AccessResult.DENIED,
                    correlationId,
                    decision.getReason());

            // Alert on suspicious patterns
            detectSuspiciousAccess(currentUser, doc, decision);

            return ResponseEntity.status(403).build();
        }

        try {
            Path filePath = Paths.get(UPLOAD_DIR)
                    .resolve(doc.getStoragePartition())
                    .resolve(doc.getStoredFilename());

            // Layer 4: Path traversal prevention
            if (!filePath.normalize().startsWith(Paths.get(UPLOAD_DIR))) {
                auditLogService.logSecurityEvent(
                        SecurityEvent.PATH_TRAVERSAL_ATTEMPT,
                        currentUser.getId(),
                        documentUuid.toString(),
                        correlationId);
                alertService.triggerAlert(AlertType.SECURITY_VIOLATION, 
                        currentUser.getId(), "Path traversal attempt");
                return ResponseEntity.status(400).build();
            }

            Resource resource = new UrlResource(filePath.toUri());

            if (!resource.exists() || !resource.isReadable()) {
                auditLogService.logAccessAttempt(
                        currentUser.getId(),
                        documentUuid.toString(),
                        AccessResult.FILE_NOT_FOUND,
                        correlationId);
                return ResponseEntity.notFound().build();
            }

            // Layer 5: Log successful access
            auditLogService.logAccessAttempt(
                    currentUser.getId(),
                    documentUuid.toString(),
                    AccessResult.SUCCESS,
                    correlationId,
                    decision.getGrantedVia());

            return ResponseEntity.ok()
                    .header(HttpHeaders.CONTENT_DISPOSITION, 
                            "attachment; filename=\"" + 
                            sanitizeFilename(doc.getOriginalFilename()) + "\"")
                    .header("X-Content-Type-Options", "nosniff")
                    .header("X-Request-ID", correlationId)
                    .body(resource);

        } catch (Exception e) {
            auditLogService.logAccessAttempt(
                    currentUser.getId(),
                    documentUuid.toString(),
                    AccessResult.ERROR,
                    correlationId);
            return ResponseEntity.status(500).build();
        }
    }

    private boolean checkRateLimit(Long userId) {
        Bucket bucket = rateLimitBuckets.computeIfAbsent(userId, 
                k -> Bucket.builder()
                        .addLimit(Bandwidth.classic(100, 
                                Refill.intervally(100, Duration.ofMinutes(1))))
                        .build());
        return bucket.tryConsume(1);
    }

    private String sanitizeFilename(String filename) {
        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
    }

    private void detectSuspiciousAccess(UserPrincipal user, Document doc, 
                                         AccessDecision decision) {
        // Detect enumeration attempts
        long recentDenials = auditLogService.countRecentDenials(
                user.getId(), Duration.ofMinutes(5));
        if (recentDenials > 10) {
            alertService.triggerAlert(
                    AlertType.POTENTIAL_ENUMERATION,
                    user.getId(),
                    "High denial rate detected: " + recentDenials + " in 5 minutes");
        }
    }
}
```

```java
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class DocumentAccessEvaluator {

    private final DocumentPermissionRepository permissionRepository;

    public DocumentAccessEvaluator(DocumentPermissionRepository permissionRepository) {
        this.permissionRepository = permissionRepository;
    }

    public AccessDecision evaluate(UserPrincipal user, Document document) {
        // Check 1: Is user the document owner?
        if (document.getOwnerId().equals(user.getId())) {
            return AccessDecision.allowed("OWNER");
        }

        // Check 2: Does user have admin role for this document's organization?
        if (user.hasRole("ADMIN") && 
            user.getOrganizationId().equals(document.getOrganizationId())) {
            return AccessDecision.allowed("ORG_ADMIN");
        }

        // Check 3: Is user a system-wide super admin?
        if (user.hasRole("SUPER_ADMIN")) {
            return AccessDecision.allowed("SUPER_ADMIN");
        }

        // Check 4: Does user have explicit share permission?
        Optional<DocumentPermission> permission = 
                permissionRepository.findByDocumentIdAndUserId(
                        document.getId(), user.getId());

        if (permission.isPresent()) {
            DocumentPermission perm = permission.get();

            // Verify permission is still valid
            if (perm.isExpired()) {
                return AccessDecision.denied("SHARE_EXPIRED");
            }

            if (!perm.getPermissionType().includes(PermissionType.READ)) {
                return AccessDecision.denied("INSUFFICIENT_PERMISSION");
            }

            return AccessDecision.allowed("SHARED:" + perm.getGrantedBy());
        }

        // Check 5: Is user in a group with access?
        List<Long> userGroupIds = user.getGroupIds();
        Optional<DocumentPermission> groupPermission = 
                permissionRepository.findByDocumentIdAndGroupIdIn(
                        document.getId(), userGroupIds);

        if (groupPermission.isPresent() && 
            !groupPermission.get().isExpired() &&
            groupPermission.get().getPermissionType().includes(PermissionType.READ)) {
            return AccessDecision.allowed("GROUP:" + groupPermission.get().getGroupId());
        }

        // Check 6: Is document public within organization?
        if (document.isOrganizationPublic() && 
            user.getOrganizationId().equals(document.getOrganizationId())) {
            return AccessDecision.allowed("ORG_PUBLIC");
        }

        // Default: Deny
        return AccessDecision.denied("NO_PERMISSION");
    }
}
```

