	userID, _ := strconv.Atoi(vars["id"])

	var user User
	err := db.QueryRow("SELECT id, username, email, ssn, is_admin FROM users WHERE id = $1", userID).Scan(
		&user.ID, &user.Username, &user.Email, &user.SSN, &user.IsAdmin)

	if err != nil {
		http.Error(w, "User not found", http.StatusNotFound)
		return
