	PublicToken  string    `json:"-"` // Cryptographically random access token
	FilePath     string    `json:"-"` // Never expose internal paths
	Filename     string    `json:"filename"`
	CreatedAt    time.Time `json:"created_at"`
	ExpiresAt    *time.Time `json:"expires_at,omitempty"`
	AccessCount  int       `json:"access_count"`
	MaxDownloads int       `json:"max_downloads"`
}

type DownloadRequest struct {
	DocumentID string `json:"document_id"`
	ExpiresIn  int    `json:"expires_in_minutes"` // Optional expiration
}

// Rate limiter per user to prevent enumeration
var userLimiters = make(map[string]*rate.Limiter)

func getUserLimiter(userID string) *rate.Limiter {
	if limiter, exists := userLimiters[userID]; exists {
		return limiter
	}
	// 10 requests per second, burst of 20
	limiter := rate.NewLimiter(10, 20)
	userLimiters[userID] = limiter
	return limiter
}

// Generate cryptographically secure token for document access
func generateSecureToken() (string, error) {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

// SECURE: Generate time-limited, single-use download URL
func generateDownloadLinkHandler(w http.ResponseWriter, r *http.Request) {
	user := r.Context().Value(userContextKey).(*User)

	// Rate limiting
	if !getUserLimiter(user.ID).Allow() {
		log.Printf("SECURITY: Rate limit exceeded for user %s", user.ID)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	var req DownloadRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate UUID format
	if _, err := uuid.Parse(req.DocumentID); err != nil {
		http.Error(w, "Invalid document ID", http.StatusBadRequest)
		return
	}

	// CRITICAL: Verify document ownership or admin access
	var doc Document
	err := db.QueryRow(`
		SELECT id, owner_id, file_path, filename 
		FROM documents 
		WHERE id = $1`, req.DocumentID).Scan(
		&doc.ID, &doc.OwnerID, &doc.FilePath, &doc.Filename)

	if err == sql.ErrNoRows {
		// Don't reveal if document exists - return generic error
		log.Printf("SECURITY: Document access attempt for non-existent doc %s by user %s",
			req.DocumentID, user.ID)
		http.Error(w, "Document not found or access denied", http.StatusNotFound)
		return
	}

	// AUTHORIZATION: Verify user owns document or is admin
	if doc.OwnerID != user.ID && !user.IsAdmin {
		log.Printf("SECURITY: Unauthorized document access attempt. User %s tried to access doc %s owned by %s",
			user.ID, doc.ID, doc.OwnerID)
		// Same error message to prevent enumeration
		http.Error(w, "Document not found or access denied", http.StatusNotFound)
		return
	}

	// Generate cryptographically secure access token
	accessToken, err := generateSecureToken()
	if err != nil {
		log.Printf("Error generating token: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Set expiration (default 15 minutes, max 60 minutes)
	expiresIn := 15
	if req.ExpiresIn > 0 && req.ExpiresIn <= 60 {
		expiresIn = req.ExpiresIn
	}
	expiresAt := time.Now().Add(time.Duration(expiresIn) * time.Minute)

	// Store token with expiration and download limit
	_, err = db.Exec(`
		INSERT INTO download_tokens (token, document_id, user_id, expires_at, max_downloads, created_at)
		VALUES ($1, $2, $3, $4, $5, NOW())`,
		accessToken, doc.ID, user.ID, expiresAt, 3) // Max 3 downloads

	if err != nil {
		log.Printf("Error storing download token: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Audit log
	log.Printf("AUDIT: Download link generated for doc %s by user %s, expires %s",
		doc.ID, user.ID, expiresAt.Format(time.RFC3339))

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"download_url": "/api/download/" + accessToken,
		"expires_at":   expiresAt,
		"filename":     doc.Filename,
	})
}

// SECURE: Download file using time-limited token
func downloadFileHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	accessToken := vars["token"]

	// Validate token format (64 hex chars)
	if len(accessToken) != 64 {
		http.Error(w, "Invalid token", http.StatusBadRequest)
		return
	}

	// Atomic: check token validity AND increment download count
	var docID, filePath, filename string
	var downloadCount, maxDownloads int
	var expiresAt time.Time

	err := db.QueryRow(`
		UPDATE download_tokens 
		SET download_count = download_count + 1
		WHERE token = $1 
		AND expires_at > NOW()
		AND download_count < max_downloads
		RETURNING document_id, download_count, max_downloads, expires_at`,
		accessToken).Scan(&docID, &downloadCount, &maxDownloads, &expiresAt)

	if err == sql.ErrNoRows {
		log.Printf("SECURITY: Invalid/expired download token used from IP %s", r.RemoteAddr)
		http.Error(w, "Download link invalid or expired", http.StatusForbidden)
		return
	} else if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Get file path from documents table
	err = db.QueryRow(`SELECT file_path, filename FROM documents WHERE id = $1`,
		docID).Scan(&filePath, &filename)
	if err != nil {
		log.Printf("Error retrieving document: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// SECURITY: Validate file path is within allowed directory
	baseDir := "/var/app/documents"
	cleanPath := filepath.Clean(filePath)
	if !filepath.HasPrefix(cleanPath, baseDir) {
		log.Printf("SECURITY: Path traversal attempt: %s", filePath)
		http.Error(w, "Invalid file", http.StatusForbidden)
		return
	}

	// Check file exists
	if _, err := os.Stat(cleanPath); os.IsNotExist(err) {
		log.Printf("ERROR: Document file not found: %s", cleanPath)
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	// Set secure headers
	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", "attachment; filename=\""+filename+"\"")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "no-store, no-cache, must-revalidate")

	log.Printf("AUDIT: File downloaded - doc %s, download %d/%d",
		docID, downloadCount, maxDownloads)

	http.ServeFile(w, r, cleanPath)
}

// Cleanup expired tokens (run as background job)
func cleanupExpiredTokens() {
	ticker := time.NewTicker(5 * time.Minute)
	for range ticker.C {
		result, err := db.Exec(`DELETE FROM download_tokens WHERE expires_at < NOW()`)
		if err != nil {
			log.Printf("Error cleaning tokens: %v", err)
			continue
		}
		rows, _ := result.RowsAffected()
		if rows > 0 {
			log.Printf("CLEANUP: Removed %d expired download tokens", rows)
		}
	}
}

func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// JWT validation implementation
		next.ServeHTTP(w, r)
	})
}

func main() {
	// Start background cleanup
	go cleanupExpiredTokens()

	r := mux.NewRouter()

	// Protected download link generation
	api := r.PathPrefix("/api").Subrouter()
	api.Use(authMiddleware)
	api.HandleFunc("/documents/{id}/download-link", generateDownloadLinkHandler).Methods("POST")

	// Token-based download (no auth required - token IS the auth)
	r.HandleFunc("/api/download/{token}", downloadFileHandler).Methods("GET")

	http.ListenAndServe(":8080", r)
}
